create table dirkspzm32.isi_arbeitsplatz (
    arbeitsplatz_id number(*, 0) not null enable,
    ip_adresse      varchar2(100 char),
    ip_name         varchar2(20 char) not null enable,
    lagerort        varchar2(10 char),
    anwendung       varchar2(20 char),
    adress_id       number(*, 0),
    orts_kz         varchar2(50 char),
    beschreibung    varchar2(255 char),
    isi_log_popup   varchar2(1 char),
    ord_verladung   varchar2(1 char),
    res_id          number(*, 0)
);

alter table dirkspzm32.isi_arbeitsplatz
    add constraint pk_arbeitsplatz primary key ( arbeitsplatz_id )
        using index enable;

alter table dirkspzm32.isi_arbeitsplatz add constraint uix_arbeitspl_ip_adresse unique ( ip_adresse )
    using index enable;


